// ============================================================================
// schema_validator (Tool #2 REQUIRED by take-home spec)
// Branded for writeup as: 'Deterministic Tool: Schema Validator'
//
// Pure deterministic JSON schema validation. No AI. Validates a candidate
// SFDC-lite payload against the take-home schema, with two modes:
//   abstain_mode: false -> full schema validation (rich update path)
//   abstain_mode: true  -> minimal validation (abstain path)
//
// Input  : { candidate_payload: object, abstain_mode: boolean }
// Output : { valid, errors[], warnings[], validated_payload }
//
// Errors are blocking (valid=false). Warnings are advisory (valid=true).
// ============================================================================

const input = $input.first().json;
const payload = input.candidate_payload;
const abstainMode = input.abstain_mode === true;

const errors = [];
const warnings = [];

const VALID_STAGES = [
  'prospecting',
  'discovery',
  'solution_design',
  'proposal',
  'negotiation',
  'closed_won',
  'closed_lost'
];

const MEDDPICC_KEYS = [
  'metrics',
  'economic_buyer',
  'decision_criteria',
  'decision_process',
  'paper_process',
  'identify_pain',
  'champion',
  'competition'
];

// Helpers ---------------------------------------------------------------
function isString(v)    { return typeof v === 'string'; }
function isNumber(v)    { return typeof v === 'number' && !Number.isNaN(v); }
function isObject(v)    { return v !== null && typeof v === 'object' && !Array.isArray(v); }
function isArray(v)     { return Array.isArray(v); }
function isISO(v)       { return isString(v) && /^\d{4}-\d{2}-\d{2}(T.*)?$/.test(v) && !Number.isNaN(Date.parse(v)); }
function isStringOrEmpty(v) { return v === '' || isString(v); }

// --- Top-level guard ---------------------------------------------------
if (!isObject(payload)) {
  return [{ json: {
    valid: false,
    errors: ['candidate_payload missing or not an object'],
    warnings: [],
    validated_payload: null
  }}];
}

// --- Always required (both modes) --------------------------------------
if (!isString(payload.opportunity_id) || payload.opportunity_id.length === 0) {
  errors.push('opportunity_id: required string');
}

if (!isString(payload.last_touch_summary) || payload.last_touch_summary.length === 0) {
  errors.push('last_touch_summary: required non-empty string');
}

if (!isNumber(payload.confidence) || payload.confidence < 0 || payload.confidence > 1) {
  errors.push('confidence: required float in [0, 1]');
}

// =======================================================================
// MODE 1: ABSTAIN
// Everything except {id, last_touch_summary, confidence} MUST be null
// =======================================================================
if (abstainMode) {
  const mustBeNull = ['stage', 'amount_usd', 'close_date', 'next_step', 'meddpicc', 'risks'];

  for (let i = 0; i < mustBeNull.length; i++) {
    const key = mustBeNull[i];
    if (payload[key] !== null && payload[key] !== undefined) {
      const got = JSON.stringify(payload[key]).substring(0, 40);
      errors.push('abstain_mode: ' + key + ' must be null (got ' + got + ')');
    }
  }

  return [{ json: {
    valid: errors.length === 0,
    errors: errors,
    warnings: warnings,
    validated_payload: errors.length === 0 ? payload : null
  }}];
}

// =======================================================================
// MODE 2: FULL UPDATE  --  rich SFDC-lite payload
// =======================================================================

// stage --------------------------------------------------------------------
if (!isString(payload.stage)) {
  errors.push('stage: required string');
} else if (VALID_STAGES.indexOf(payload.stage) === -1) {
  errors.push('stage: must be one of ' + VALID_STAGES.join('|') + ' (got "' + payload.stage + '")');
}

// amount_usd ---------------------------------------------------------------
if (payload.amount_usd !== null && payload.amount_usd !== undefined) {
  if (!isNumber(payload.amount_usd)) {
    errors.push('amount_usd: must be a number or null');
  } else if (payload.amount_usd < 0) {
    errors.push('amount_usd: must be non-negative');
  }
}

// close_date ---------------------------------------------------------------
if (payload.close_date !== null && payload.close_date !== undefined) {
  if (!isISO(payload.close_date)) {
    errors.push('close_date: must be ISO date (got "' + payload.close_date + '")');
  }
}

// next_step ----------------------------------------------------------------
if (payload.next_step !== null && payload.next_step !== undefined) {
  if (!isObject(payload.next_step)) {
    errors.push('next_step: must be an object or null');
  } else {
    if (!isString(payload.next_step.description) || payload.next_step.description.length === 0) {
      errors.push('next_step.description: required non-empty string');
    }
    if (!isString(payload.next_step.owner) || payload.next_step.owner.length === 0) {
      errors.push('next_step.owner: required non-empty string');
    }
    if (!isISO(payload.next_step.due_date)) {
      errors.push('next_step.due_date: must be ISO date (got "' + payload.next_step.due_date + '")');
    }
  }
} else {
  warnings.push('next_step: null in update mode (uncommon for rich-signal calls)');
}

// meddpicc -----------------------------------------------------------------
if (!isObject(payload.meddpicc)) {
  errors.push('meddpicc: required object with 8 string fields');
} else {
  for (let i = 0; i < MEDDPICC_KEYS.length; i++) {
    const k = MEDDPICC_KEYS[i];
    if (!isStringOrEmpty(payload.meddpicc[k])) {
      errors.push('meddpicc.' + k + ': must be a string (use "" if no signal, never null)');
    }
  }
  let filled = 0;
  for (let i = 0; i < MEDDPICC_KEYS.length; i++) {
    const v = payload.meddpicc[MEDDPICC_KEYS[i]];
    if (v && v.length > 0) filled++;
  }
  if (filled === 0) {
    warnings.push('meddpicc: all 8 fields empty in update mode (rich-signal call expected at least one)');
  }
}

// risks --------------------------------------------------------------------
if (!isArray(payload.risks)) {
  errors.push('risks: must be an array (use [] if none)');
} else {
  for (let i = 0; i < payload.risks.length; i++) {
    if (!isString(payload.risks[i]) || payload.risks[i].length === 0) {
      errors.push('risks[' + i + ']: must be a non-empty string');
    }
  }
}

// --- Final response ----------------------------------------------------
return [{ json: {
  valid: errors.length === 0,
  errors: errors,
  warnings: warnings,
  validated_payload: errors.length === 0 ? payload : null
}}];
